mapper.select:
SELECT t1.id, t1.entrustment_id, t1.report_code, t1.sample_name, t1.required_completion_time, t1.report_url, t1.number, t1.issuer_time, t1.seal_type, t1.sealer, t1.seal_time, t1.type, t1.category, t1.qys_state, t1.contract_id FROM test_report_record t1 LEFT JOIN test_task t3 ON t1.entrustment_id = t3.entrustment_id WHERE t1.state >= 7
AND t3.dept_id IN
#{id}
AND report_code like concat(concat('%',#{reportCode}),'%')
AND type = #{reportType}
AND category = #{sealType}
